#include <bits/stdc++.h>
using namespace std;
int main(){
    long long S; cin >> S;
    long long c[] = {500000,200000,100000,50000,20000,10000,5000,2000,1000,500,200,100};
    long long cnt[12]={0}; long long total = 0;
    for (int i = 0; i < 12; i++){
        cnt[i] = S / c[i];
        S -= cnt[i] * c[i];
        total += cnt[i];
    }
    cout << total << '\n';
    for (int i = 0; i < 12; i++) cout << c[i] << ' ' << cnt[i] << '\n';
}
